def solve(packet: str) -> int: # Assume packet format is "data1:data2:...:checksum" or "data1|data2|...|checksum"
    # We compute checksum from the data portion

    # Try common delimiters
    for delimiter in [':', '|', ',']:
        if delimiter in packet:
            parts = packet.split(delimiter)
            if len(parts) >= 2:
                # Compute checksum from all parts except the last (which is the original checksum)
                data_parts = parts[:-1]
                checksum = sum(ord(c) for part in data_parts for c in part)
                return checksum

    # If no delimiter found, compute checksum from entire packet
    return sum(ord(c) for c in packet)

