import re
from typing import Any

# Constants and patterns needed for validation
_TOKEN_PATTERN = re.compile(r'^[A-Za-z0-9]{2,}$')
_VALID_VERSIONS = {1, 2, 3}
_CHECKSUM_MODULUS = {1: 89, 2: 97, 3: 113}


def decode_fluxon_frame(frame: str) -> str:
    """Decode a Fluxon frame into a packet string."""
    if not (frame.startswith("[FXN:") and frame.endswith(":END]")):
        raise ValueError(f"Invalid Fluxon frame: {frame!r}")
    inner = frame[5:-5]
    if not inner.startswith("FXN::"):
        raise ValueError(f"Frame does not contain a Fluxon packet: {frame!r}")
    return inner


def parse_fluxon_packet(packet: str) -> dict[str, Any]:
    """Parse a Fluxon packet string into a record."""
    inner = decode_fluxon_frame(packet) if packet.startswith("[FXN:") else packet

    parts = inner.split("::")
    if len(parts) < 5:
        raise ValueError(f"Invalid packet format: {inner}")

    # Format: FXN::version::channel::payload::token1::token2::...::checksum
    if parts[0] != "FXN":
        raise ValueError(f"Invalid packet prefix: {parts[0]}")

    version = int(parts[1])
    channel = parts[2]
    payload = parts[3]

    # Tokens and checksum
    tokens_and_checksum = parts[4:]
    if not tokens_and_checksum:
        raise ValueError("Missing checksum")

    checksum = int(tokens_and_checksum[-1])
    tokens = tokens_and_checksum[:-1]

    return {
        "version": version,
        "channel": channel,
        "payload": payload,
        "tokens": tokens,
        "checksum": checksum
    }


def split_fluxon_payload(payload: str) -> list[str]:
    """Split a payload string by dashes."""
    if not payload:
        return []
    return payload.split("-")


def token_value(token: str) -> int:
    """Compute the value of a token (sum of char ordinals)."""
    return sum(ord(c) for c in token)


def compute_fluxon_checksum(payload: str, version: int) -> int:
    """Compute the checksum of a payload for a given version."""
    if version not in _VALID_VERSIONS:
        raise ValueError(f"Invalid version: {version}")
    tokens = split_fluxon_payload(payload)
    total = sum(token_value(t) for t in tokens)
    return total % _CHECKSUM_MODULUS[version]


