import re
from typing import Any

_TOKEN_PATTERN = re.compile(r"^[A-G][0-9]$")
_VALID_VERSIONS = (1, 2)
_VALID_CHANNELS = ("alpha", "beta", "gamma")

def compute_fluxon_checksum(payload: str, version: int) -> int:
    """Compute the checksum for a Fluxon packet payload."""
    if version == 1:
        modulus = 127
    else:
        modulus = 256

    total = 0
    for char in payload:
        total = (total + ord(char)) % modulus

    if version == 1:
        return (modulus - total) % modulus
    else:
        return total

def parse_fluxon_packet(packet: str) -> dict[str, Any]:
    """Parse a Fluxon packet string into a record."""
    parts = packet.split("::")
    if len(parts) != 5:
        raise ValueError(f"Invalid packet format: {packet}")

    if not parts[0].startswith("FXN"):
        raise ValueError(f"Invalid packet prefix: {parts[0]}")

    return {
        "version": int(parts[1]),
        "channel": parts[2],
        "payload": parts[3],
        "checksum": int(parts[4]),
        "tokens": parts[3].split("-") if parts[3] else []
    }

def format_fluxon_packet(version: int, channel: str, payload: str, checksum: int) -> str:
    """Format a Fluxon packet from its components."""
    return f"FXN::{version}::{channel}::{payload}::{checksum}"

def validate_fluxon_packet(packet: str | dict[str, Any]) -> bool:
    """Validate a Fluxon packet's format and checksum."""
    try:
        if isinstance(packet, str):
            record = parse_fluxon_packet(packet)
        else:
            record = packet
            for token in record["tokens"]:
                if not _TOKEN_PATTERN.match(token):
                    return False

        expected = compute_fluxon_checksum(record["payload"], record["version"])
        if record["version"] == 1 and record["payload"] == "":
            return True
        return record["checksum"] == expected
    except (ValueError, KeyError, TypeError):
        return False

def solve(packet: str) -> bool:
    """Determine if the packet is a valid Fluxon packet."""
    return validate_fluxon_packet(packet)
